class Solution:
    def beautifulIndices(self, s: str, a: str, b: str, k: int) -> List[int]:
        def kmp(text, pat):
            if not pat:
                return []
            n, m = len(text), len(pat)
            lps = [0]*m
            j = 0
            for i in range(1, m):
                while j and pat[i] != pat[j]:
                    j = lps[j-1]
                if pat[i] == pat[j]:
                    j += 1
                    lps[i] = j
            res = []
            j = 0
            for i in range(n):
                while j and text[i] != pat[j]:
                    j = lps[j-1]
                if text[i] == pat[j]:
                    j += 1
                    if j == m:
                        res.append(i-m+1)
                        j = lps[j-1]
            return res

        A = kmp(s, a)
        B = kmp(s, b)
        if not A or not B:
            return []

        res = []
        m = len(B)
        left = 0
        for i in A:
            low = i - k
            high = i + k
            while left < m and B[left] < low:
                left += 1
            if left < m and B[left] <= high:
                res.append(i)
        return res
